// Shared inner-page hero banner

interface Props {
  badge?: string;
  title: string;
  highlight?: string;
  subtitle?: string;
  breadcrumb?: { label: string; href?: string }[];
}

export default function PageHero({
  badge,
  title,
  highlight,
  subtitle,
  breadcrumb,
}: Props) {
  return (
    <section className="pt-36 pb-20 relative overflow-hidden" style={{ background: "var(--dark)" }}>
      {/* Decorative grid lines */}
      <div
        className="absolute inset-0 opacity-[0.03]"
        style={{
          backgroundImage:
            "linear-gradient(rgba(255,255,255,.5) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,.5) 1px, transparent 1px)",
          backgroundSize: "60px 60px",
        }}
      />

      {/* Glow accent */}
      <div className="absolute -top-40 -right-40 w-[500px] h-[500px] bg-[--primary]/10 rounded-full blur-[100px]" />

      <div className="container-xl relative z-10">
        {/* Breadcrumb */}
        {breadcrumb && (
          <ol className="flex items-center gap-2 mb-6">
            {breadcrumb.map((crumb, i) => (
              <li key={i} className="flex items-center gap-2">
                {i > 0 && <span className="text-white/20 text-xs">›</span>}
                {crumb.href ? (
                  <a href={crumb.href} className="text-xs text-white/40 hover:text-white/70 transition-colors">
                    {crumb.label}
                  </a>
                ) : (
                  <span className="text-xs text-white/60">{crumb.label}</span>
                )}
              </li>
            ))}
          </ol>
        )}

        {/* Badge */}
        {badge && (
          <div className="inline-flex items-center gap-2 bg-[--primary]/15 border border-[--primary]/30 rounded-full px-4 py-1.5 mb-6">
            <span className="text-xs text-[--primary] font-semibold tracking-[.1em] uppercase">{badge}</span>
          </div>
        )}

        {/* Title */}
        <h1 className="heading-2 font-bold text-white max-w-3xl leading-tight mb-5">
          {title}
          {highlight && (
            <>
              {" "}
              <span className="hl-gradient">{highlight}</span>
            </>
          )}
        </h1>

        {/* Subtitle */}
        {subtitle && (
          <p className="text-white/60 text-lg max-w-xl leading-relaxed">{subtitle}</p>
        )}
      </div>
    </section>
  );
}
